/** 查找某年的节气时刻 */
export function getYearJieqi(year: number): YearJieqi | undefined {
  return JIEQI_TABLE.find(j => j.year === year);
}

/** 查找某年某个节气的精确时刻 [month, day, hour, minute] */
export function getJieqiMoment(year: number, name: string): JieqiMoment | undefined {
  const yj = getYearJieqi(year);
  if (!yj) return undefined;
  const idx = JIEQI_INDEX[name];
  if (idx === undefined) return undefined;
  return yj.items[idx];
}
